refsection.programlisting:
// load the database associated to the "small" model:
global GROCERDIR;
load(GROCERDIR+'\data\small_db.dat')
// print the values of the variables demon, time, trim and trim2 in this database for the
// period 1990q1 to 2006q4
prt_tsmat('level',['1990q1';'2006q4'],list('small_db'),['demmon';'time';'trim1';'trim2'])
// print the growth rate of the variables demon, td_pib1, td_pib3 and td_pib5 in this database for the
// period 2006q1 to 2007q4
prt_tsmat('growth rate',['1990q1';'2006q4'],list('small_db'),['demmon';'td_pib1';'td_pib3';'td_pib5'])

load(GROCERDIR+'\data\small.dat')
// load the database small_db
// simulate the small model with database small_db from 1981q1 to 2006q4, keeping
// the data from 1978q1 and using the lagged endogenous variables as starting values
sim_histo=simulate(small,small_db,'1981q1','2006q4',1,'1978q1','2006q4') 
// display the comparison of simulation results with the original database small_db
// for variables td_pib1 and td_pib3 
prt_tsmat('pcer',['1990q1';'2006q4'],list('small_db','sim_histo(''simulation results'')'),['td_pib1','td_pib3'])
